import{c as a,Q as t,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Multi-Agent Memory from a Computer Architecture Perspective: Visions and Challenges Ahead","description":"","frontmatter":{"title":"Multi-Agent Memory from a Computer Architecture Perspective: Visions and Challenges Ahead","arxiv_id":2603.10062,"authors":"Zhongming Yu, Naicheng Yu, Hejia Zhang, et al.","published":"2026-03-09T00:00:00.000Z","source":"https://arxiv.org/abs/2603.10062","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-03-09-multi-agent-memory-computer-architecture-2603-10062.md","filePath":"research/papers/2026-03-09-multi-agent-memory-computer-architecture-2603-10062.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-03-09-multi-agent-memory-computer-architecture-2603-10062.md"};function i(s,e,h,l,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="multi-agent-memory-from-a-computer-architecture-perspective-visions-and-challenges-ahead" tabindex="-1">Multi-Agent Memory from a Computer Architecture Perspective: Visions and Challenges Ahead <a class="header-anchor" href="#multi-agent-memory-from-a-computer-architecture-perspective-visions-and-challenges-ahead" aria-label="Permalink to &quot;Multi-Agent Memory from a Computer Architecture Perspective: Visions and Challenges Ahead&quot;">​</a></h1><p><strong>ArXiv</strong>: 2603.10062 | <strong>Date</strong>: 2026-03-09 (修訂 2026-03-30) | <strong>Authors</strong>: Zhongming Yu, Naicheng Yu, Hejia Zhang, et al. | <strong>Category</strong>: cs.AR, cs.AI, cs.MA</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>Position paper，將多 agent 記憶管理重新框架為<strong>計算機架構問題</strong>，從 CS 傳統系統設計借鑑概念。隨著 LLM agent 演化為協作型多 agent 系統，本文提供正式架構框架。</p><h2 id="核心框架" tabindex="-1">核心框架 <a class="header-anchor" href="#核心框架" aria-label="Permalink to &quot;核心框架&quot;">​</a></h2><h3 id="記憶範式區分" tabindex="-1">記憶範式區分 <a class="header-anchor" href="#記憶範式區分" aria-label="Permalink to &quot;記憶範式區分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>範式</th><th>描述</th></tr></thead><tbody><tr><td>共享記憶（Shared Memory）</td><td>agent 存取共同資源（類比 SMP）</td></tr><tr><td>分散記憶（Distributed Memory）</td><td>各 agent 維護獨立記憶系統（類比分散式計算）</td></tr></tbody></table><h3 id="三層記憶階層" tabindex="-1">三層記憶階層 <a class="header-anchor" href="#三層記憶階層" aria-label="Permalink to &quot;三層記憶階層&quot;">​</a></h3><p>借鑑傳統計算機架構原則：</p><ol><li><strong>I/O 層</strong>：agent 與外部世界的記憶交換</li><li><strong>快取層</strong>（Cache）：高頻訪問記憶的快速存取</li><li><strong>主記憶層</strong>（Primary memory）：持久化長期記憶</li></ol><h3 id="識別的協議空白" tabindex="-1">識別的協議空白 <a class="header-anchor" href="#識別的協議空白" aria-label="Permalink to &quot;識別的協議空白&quot;">​</a></h3><p>兩個關鍵缺口：</p><ul><li><strong>跨 agent 的快取共享</strong>（Cache sharing across agents）</li><li><strong>結構化記憶存取控制</strong>（Structured memory access control）</li></ul><h2 id="最緊迫的開放挑戰" tabindex="-1">最緊迫的開放挑戰 <a class="header-anchor" href="#最緊迫的開放挑戰" aria-label="Permalink to &quot;最緊迫的開放挑戰&quot;">​</a></h2><p><strong>多 agent 記憶一致性</strong>：當多個 agent 同時存取或修改共享資訊時，確保系統維持一致、可靠的資料狀態。</p><p>對應傳統計算機架構的「快取一致性（Cache Coherency）問題」，但在 LLM agent 環境中更難解決（語義豐富性、非確定性推理）。</p><h2 id="學術意義" tabindex="-1">學術意義 <a class="header-anchor" href="#學術意義" aria-label="Permalink to &quot;學術意義&quot;">​</a></h2><p>主張橋接兩個傳統上分開的領域：計算機架構 ＋ 人工智能。</p><p>傳統多核處理器的快取一致性解決方案（MESI 協議等）可能為多 agent 記憶一致性提供設計啟發。</p><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>與 <code>2026-05-05-coordination-architectural-layer</code> 互補：</p><ul><li>前者從「協調」視角（agent 間通訊協議）</li><li>本文從「記憶」視角（共享狀態一致性）</li></ul><p>多 agent fan-out 設計中「child 間不直接溝通」的規則，部分原因正是為了避免共享記憶一致性問題。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture / Agent Architecture &amp; Coordination</strong> — 首篇從計算機架構視角系統性分析多 agent 記憶的 position paper，為多 agent 系統的基礎架構設計提供理論基礎。</p>',25)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
